class Solution:
    def maxMatrixSum(self, matrix):
        total = 0
        neg = 0
        smallest = None
        for row in matrix:
            for v in row:
                a = abs(v)
                total += a
                if v < 0:
                    neg += 1
                if smallest is None or a < smallest:
                    smallest = a
        if neg % 2 == 0:
            return total
        return total - 2 * smallest

