class Solution:
    def maxMatrixSum(self, matrix):
        total = 0
        neg = 0
        mn = float('inf')
        for row in matrix:
            for v in row:
                a = abs(v)
                total += a
                mn = min(mn, a)
                if v < 0:
                    neg += 1
        return total if neg % 2 == 0 else total - 2 * mn

