var maxMatrixSum = function(matrix) {
    let total = 0, neg = 0, mn = Infinity;
    for (const row of matrix) {
        for (const v of row) {
            const a = Math.abs(v);
            total += a;
            if (a < mn) mn = a;
            if (v < 0) neg++;
        }
    }
    return neg % 2 === 0 ? total : total - 2 * mn;
};
